import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { createVectorStoreAgent } from './rag-store';

const store = createVectorStoreAgent();

export async function streamRAG(query: string) {
  const results = await store.similaritySearch(query, 5);
  const context = results.map((doc) => doc.pageContent).join('\n\n');

  const { textStream } = await streamText({
    model: openai('gpt-4o'),
    prompt: `Answer using ONLY this context:\n\n${context}\n\nQuery: ${query}\n\nInclude [1], [2] citations.`
  });

  return textStream;
}

import { createStreamableValue } from 'ai/rsc';
import { streamRAG } from './rag-stream';

export default async function RAGChat({ query }: { query: string }) {
  const [messages, setMessages] = createStreamableValue('');

  (async () => {
    try {
      const stream = await streamRAG(query);
      for await (const chunk of stream) {
        setMessages((current) => current + chunk);
      }
    } catch (error) {
      setMessages('Error generating response');
    }
  })();

  return <div>{messages.value}</div>;
}

import { Pinecone } from '@pinecone-database/pinecone';
import { OpenAIEmbeddings } from '@langchain/openai';

const pinecone = new Pinecone({ apiKey: process.env.PINECONE_API_KEY! });
const embeddings = new OpenAIEmbeddings();

const index = pinecone.index('rag-docs');

export async function createVectorStoreAgent() {
  return {
    async similaritySearch(query: string, k: number) {
      const queryEmbedding = await embeddings.embedQuery(query);
      const results = await index.query({
        vector: queryEmbedding,
        topK: k,
        includeMetadata: true
      });
      return results.matches!.map((match) => ({
        pageContent: match.metadata!.text as string,
        metadata: { source: match.metadata!.source }
      }));
    }
  };
}

const RAG_PROMPT = `
You are a helpful assistant. Answer the QUERY using ONLY the CONTEXT below.

CONTEXT:
{{CONTEXT}}

QUERY: {{QUERY}}

Guidelines:
1. Use ONLY information from CONTEXT - no external knowledge
2. Cite sources after each fact: [1], [2], etc.
3. Sources listed at end: [1] filename.pdf p.5
4. If unsure, say "I don't have enough context"

RESPONSE:
`;

export function formatRAGPrompt(query: string, context: string[]) {
  const numberedContext = context.map((doc, i) => `\n[${i + 1}] ${doc}`).join('');
  return RAG_PROMPT
    .replace('{{CONTEXT}}', numberedContext)
    .replace('{{QUERY}}', query);
}

