import { createVex } from '@vex_dev/sdk';
import { streamText } from 'ai';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!
});

export async function streamRAGWithVex(query: string, context: any[]) {
  const result = await vex.verify({
    useCase: 'rag-pipeline',
    inputs: { query },
    context: {
      sources: context,
      faithfulness: true,
      hallucination: 'strict',
      citations: true
    },
    async ({ pass, reject }) => {
      const { textStream } = await streamText({
        model: openai('gpt-4o'),
        prompt: formatRAGPrompt(query, context)
      });

      return {
        stream: textStream,
        pass,
        reject
      };
    }
  });

  return result.verifiedStream;
}

import { createVex } from '@vex_dev/sdk';

const vex = createVex({ /* config */ });

export async function validateRAGContext(query: string, docs: any[]) {
  const { verdict, score } = await vex.run({
    useCase: 'rag-context-check',
    inputs: { query },
    context: { documents: docs },
    checks: [
      {
        type: 'relevance',
        threshold: 0.8,
        rejectLow: true
      },
      {
        type: 'hallucination',
        mode: 'strict',
        sources: docs.map(d => d.pageContent)
      }
    ]
  });

  if (!verdict.pass) {
    throw new Error(`Context validation failed: ${verdict.reason}`);
  }

  return docs.filter((_, i) => verdict.relevantIndices.includes(i));
}

import { createVex } from '@vex_dev/sdk';

const vex = createVex({ /* config */ });

export async function verifyCitations(response: string, sources: any[]) {
  const { verdict } = await vex.run({
    useCase: 'rag-citations',
    inputs: { response },
    context: {
      sources: sources.map(s => ({ content: s.pageContent, source: s.metadata.source })),
      extractCitations: true
    },
    checks: [
      {
        type: 'citations',
        requireAll: true,
        validateContent: true,
        sourceMatch: 'exact'
      }
    ]
  });

  return {
    citationsValid: verdict.pass,
    missing: verdict.missingCitations,
    invalid: verdict.invalidCitations
  };
}
